async (page) => {
  // Simulate HTML5 DnD: drag "source" above "time"
  const result = await page.evaluate(() => {
    const items = document.querySelectorAll('.col-toggle-item');
    const sourceItem = items[2]; // "source" is at index 2
    const timeItem = items[0];  // "time" is at index 0

    // Create DataTransfer mock
    const dt = new DataTransfer();

    // 1. dragstart on source item
    const dragStartEvent = new DragEvent('dragstart', {
      bubbles: true,
      cancelable: true,
      dataTransfer: dt
    });
    sourceItem.dispatchEvent(dragStartEvent);

    // 2. dragover on time item (position above it — top half)
    const timeRect = timeItem.getBoundingClientRect();
    const dragOverEvent = new DragEvent('dragover', {
      bubbles: true,
      cancelable: true,
      dataTransfer: dt,
      clientX: timeRect.left + timeRect.width / 2,
      clientY: timeRect.top + 5 // top portion = drop above
    });
    timeItem.dispatchEvent(dragOverEvent);

    // 3. drop on time item
    const dropEvent = new DragEvent('drop', {
      bubbles: true,
      cancelable: true,
      dataTransfer: dt,
      clientX: timeRect.left + timeRect.width / 2,
      clientY: timeRect.top + 5
    });
    timeItem.dispatchEvent(dropEvent);

    // 4. dragend on source item
    const dragEndEvent = new DragEvent('dragend', {
      bubbles: true,
      cancelable: true,
      dataTransfer: dt
    });
    sourceItem.dispatchEvent(dragEndEvent);

    // Check new panel order
    const newItems = document.querySelectorAll('.col-toggle-item');
    const newOrder = [];
    for (const item of newItems) {
      newOrder.push(item.getAttribute('data-col-id'));
    }

    // Check new table headers
    const headers = [];
    document.querySelectorAll('table thead th').forEach(th => headers.push(th.textContent));

    // Check localStorage
    const stored = localStorage.getItem('instnews_column_order');

    return { newPanelOrder: newOrder, tableHeaders: headers, localStorage: stored };
  });

  return JSON.stringify(result);
}

