async (page) => {
  // Open column settings panel
  await page.click('#btn-col-settings');

  // Toggle Summary off
  const result = await page.evaluate(() => {
    // Find the Summary toggle item and click its checkbox
    const items = document.querySelectorAll('.col-toggle-item');
    let summaryToggle = null;
    for (const item of items) {
      if (item.getAttribute('data-col-id') === 'summary') {
        summaryToggle = item.querySelector('input[type="checkbox"]');
        break;
      }
    }
    if (summaryToggle) summaryToggle.click();

    // Get headers after toggling off
    const headers = [];
    document.querySelectorAll('table thead th').forEach(th => headers.push(th.textContent));

    return { headersAfterHide: headers };
  });

  return JSON.stringify(result);
}

