      clientX: sourceRect.left + sourceRect.width / 2,
      clientY: sourceRect.top + 5
    }));

    // dragend
    sentimentItem.dispatchEvent(new DragEvent('dragend', {
      bubbles: true, cancelable: true, dataTransfer: dt
    }));

    // Verify results
    const newItems = document.querySelectorAll('.col-toggle-item');
    const newOrder = [];
    for (const item of newItems) newOrder.push(item.getAttribute('data-col-id'));

    const headers = [];
    document.querySelectorAll('table thead th').forEach(th => headers.push(th.textContent));

    // Check body row sync
    const firstRow = document.querySelector('table tbody tr');
    const cells = [];
    if (firstRow) firstRow.querySelectorAll('td').forEach(td => cells.push(td.textContent.trim().substring(0, 30)));

    const stored = localStorage.getItem('instnews_column_order');

    return { newPanelOrder: newOrder, tableHeaders: headers, firstRowCells: cells, localStorage: stored };
  });

  return JSON.stringify(result);
})(page);
